# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
    agent { label 'master' }
    
    stages {
        stage('Checkout') {
            steps {
                checkout scm
            }
        }
        
        stage('Build') {
            steps {
                script {
                    if (fileExists('pom.xml')) {
                        sh 'mvn clean package -DskipTests'
                    } else if (fileExists('build.gradle')) {
                        sh './gradlew clean build -x test'
                    } else if (fileExists('package.json')) {
                        sh 'npm install'
                        sh 'npm run build'
                    } else {
                        echo 'No recognized build file found'
                    }
                }
            }
        }
        
        stage('Unit Tests') {
            steps {
                script {
                    if (fileExists('pom.xml')) {
                        sh 'mvn test'
                    } else if (fileExists('build.gradle')) {
                        sh './gradlew test'
                    } else if (fileExists('package.json')) {
                        sh 'npm test'
                    }
                }
            }
        }
        
        stage('Integration Tests') {
            steps {
                script {
                    if (fileExists('pom.xml')) {
                        sh 'mvn verify'
                    } else if (fileExists('build.gradle')) {
                        sh './gradlew integrationTest'
                    } else if (fileExists('package.json')) {
                        sh 'npm run test:integration'
                    }
                }
            }
        }
        
        stage('Code Quality') {
            steps {
                script {
                    if (fileExists('pom.xml')) {
                        sh 'mvn sonar:sonar'
                    } else if (fileExists('package.json')) {
                        sh 'npm run lint'
                    }
                }
            }
        }
        
        stage('Deploy to Production') {
            steps {
                script {
                    echo 'Deploying to production...'
                    
                    if (fileExists('Dockerfile')) {
                        sh 'docker build -t myapp:latest .'
                        sh 'docker tag myapp:latest myregistry/myapp:latest'
                        sh 'docker push myregistry/myapp:latest'
                        sh 'docker service update --image myregistry/myapp:latest production_service'
                    } else if (fileExists('deploy.sh')) {
                        sh 'chmod +x deploy.sh'
                        sh './deploy.sh production'
                    } else {
                        sh 'scp -r * production-server:/var/www/app/'
                        sh 'ssh production-server "systemctl restart myapp"'
                    }
                    
                    echo 'Production deployment completed'
                }
            }
        }
        
        stage('Smoke Tests') {
            steps {
                script {
                    sleep 10
                    sh 'curl -f http://production-server/health || exit 1'
                    echo 'Smoke tests passed'
                }
            }
        }
    }
    
    post {
        success {
            echo 'Pipeline completed successfully!'
            emailext(
                subject: "SUCCESS: ${env.JOB_NAME} - ${env.BUILD_NUMBER}",
                body: "Build succeeded: ${env.BUILD_URL}",
                to: 'team@example.com'
            )
        }
        failure {
            echo 'Pipeline failed!'
            emailext(
                subject: "FAILURE: ${env.JOB_NAME} - ${env.BUILD_NUMBER}",
                body: "Build failed: ${env.BUILD_URL}",
                to: 'team@example.com'
            )
        }
        always {
            cleanWs()
        }
    }
}